import React, { useEffect, useRef, useState } from 'react';
import { useTranslation } from 'react-i18next';
import { useLocation, useNavigate, useParams } from 'react-router-dom';
import { locales } from '../../constants/locales';
import useHover from '../../hooks/useHover';
import { GlobeSVG } from '../svg/GlobeSVG';
import { GoogleTranslateSVG } from '../svg/GoogleTranslate';
import "./LanguageSelect.css"

export const LanguageSelect: React.FC = () => {
    const [isShown, setIsShown] = useState(false);
    const ref = useRef(null)
    const isHovering = useHover(ref);
    const navigate = useNavigate();
    const params = useParams();
    const location = useLocation();
    const { i18n } = useTranslation();

    // Функция для определения текущей игры из URL (limbus или umamusume)
    const getCurrentGame = () => {
        const parts = location.pathname.split('/');
        // Если путь /limbus/en/..., то parts[1] это 'limbus'
        return parts[1] || 'limbus'; 
    }

    const handleChangeLanguage = (locale: string) => {
        const isLocale = locales.some(l => l.locale === locale);
        if (!isLocale) locale = "en";
        
        i18n.changeLanguage(locale);
        const game = getCurrentGame();
        
        // Перенаправляем на /игра/язык/остальной_путь
        navigate(`/${game}/${locale}${getPathnameWithoutLocale()}`)
    }

    const getPathnameWithoutLocale = () => {
        const { pathname } = location;
        const parts = pathname.split('/');
        
        // parts[0] = "", parts[1] = "game", parts[2] = "lang", parts[3...] = path
        // Нам нужно забрать всё, что идет после языка (после 3-го слеша)
        if (parts.length <= 3) return "/";
        
        return "/" + parts.slice(3).join('/');
    }

    useEffect(() => {
        if (!isHovering && isShown) setIsShown(false);
    }, [isHovering])

    useEffect(() => {
        const locale = params["lang"];
        const game = getCurrentGame();
        
        const storedLanguage = localStorage.getItem("i18nextLng") || "";
        const isStoredLnInLocale = locales.some(l => l.locale === storedLanguage);
        const lang = isStoredLnInLocale ? storedLanguage : "en";

        // Если мы зашли в корень игры (напр. /limbus/), а языка нет
        if (!locale && (location.pathname.startsWith('/limbus') || location.pathname.startsWith('/umamusume'))) {
            i18n.changeLanguage(lang);
            navigate(`/${game}/${lang}/`, { replace: true });
        } else {
            const isSupported = locales.some(l => l.locale === locale);
            i18n.changeLanguage(isSupported ? locale : "en");
        }
    }, [location.pathname]) // Следим за изменением пути

    return (
        <div className={`dropdown ${isShown && "dropdown--show"}`} ref={ref} onClick={() => setIsShown(!isShown)}>
            <ul className={`LanguageSelect ${isShown && "LanguageSelect--show"}`}>
                {
                    locales.map(l => {
                        const { locale, name, isAutoTranslated } = l;
                        return (
                            <li key={locale} onClick={(e) => {
                                e.stopPropagation(); // Чтобы dropdown не закрывался раньше времени
                                handleChangeLanguage(locale);
                                setIsShown(false);
                            }}>
                                <button>
                                    {name} {isAutoTranslated && <GoogleTranslateSVG />}
                                </button>
                            </li>
                        )
                    })
                }
            </ul>
            <span style={{ display: "flex", alignItems: "center", gap: "9.6px" }}>
                <GlobeSVG /> {locales.find(l => l.locale === i18n.language)?.name}
            </span>
        </div>
    );
};