import { useQuery, QueryClient } from "react-query";
import { SUPABASE_URL, SUPABASE_ANON_KEY } from "../tools/supabaseClient";
import { md_giftsKeys } from "../constants/md-giftsKeys";
import { MDGift } from "../store/reducers/md-gift-interface";

const CACHE_KEY = 'md-gifts_cache';
const CACHE_TIME = 15 * 60 * 1000; 

const getDataFromCache = () => {
  if (typeof window === 'undefined') return null;
  const cachedData = localStorage.getItem(CACHE_KEY);
  if (cachedData) {
    const { data, timestamp } = JSON.parse(cachedData);
    if (Date.now() - timestamp < CACHE_TIME) return data;
  }
  return null;
};

const setDataToCache = (data: MDGift[]) => {
  localStorage.setItem(CACHE_KEY, JSON.stringify({ data, timestamp: Date.now() }));
};

const useFetchGiftsAction = async (): Promise<MDGift[]> => {
  const cached = getDataFromCache();
  if (cached) return cached;

  // Имя таблицы в Supabase обычно md_gifts
  const url = `${SUPABASE_URL}/rest/v1/md_gifts?select=*&apikey=${SUPABASE_ANON_KEY}`;
  
  const response = await fetch(url);
  if (!response.ok) throw new Error("Ошибка загрузки MD Gifts");

  const rawData = await response.json();

  const validatedData = rawData.map((row: any) => {
    const item = {} as MDGift;
    
    md_giftsKeys.forEach(({ key, validation }) => {
      // Поддержка регистра колонок (nameRU vs nameru)
      const rawValue = row[key] !== undefined ? row[key] : row[key.toLowerCase()];
      
      const { validatedVal } = validation(rawValue ?? "");
      
      // Типизированное присваивание
      (item as any)[key] = validatedVal;
    });

    return item;
  });

  setDataToCache(validatedData);
  return validatedData;
};

export const useFetchMDGifts = () => {
  return useQuery<MDGift[]>("md-gifts", useFetchGiftsAction, {
    staleTime: CACHE_TIME,
    cacheTime: Infinity,
    refetchOnWindowFocus: false,
    retry: 5,
    onError: (error) => {
      console.error("Error fetching md-gifts from Supabase:", error);
    },
  });
};

export const createQueryClient = () => {
  const queryClient = new QueryClient({
    defaultOptions: { queries: { staleTime: CACHE_TIME, cacheTime: Infinity } },
  });

  if (typeof window !== 'undefined') {
    const cachedData = getDataFromCache();
    if (cachedData) {
      queryClient.setQueryData("md-gifts", cachedData);
    }
  }
  return queryClient;
};