import React, { useState } from 'react';
import { useTranslation } from 'react-i18next';
import { useQueryClient } from 'react-query';
import { useParams } from 'react-router-dom';
import { SEOHelmet } from '../../pages/SEOHelmet';
import { UptieComponent } from './uptie-module/uptie-component';
import { EGOInterface } from '../../store/reducers/ego-reducer';
import { LanguageDisclaimer } from '../language-disclaimer/LanguageDisclaimer';
import { EntityFullInfoEGO } from './entity-full-info-ego/EntityFullInfoEGO';
import { EntityFullInfoSkillsEGO } from './entity-full-info-skills-ego/EntityFullInfoSkillsEGO';
import "./EntityFullInfo.css"

export const EntityFullInfoEGOMain = () => {
    const { egoId } = useParams();
    const entities = useQueryClient().getQueryData('ego') as EGOInterface[];
    const entity = entities.find(id => id.imgUrl === egoId);
    const { i18n, t } = useTranslation();
    const [uptieValue, setUptieValue] = useState(4);
    if (!entity) return null;

    // Извлекаем statusUnik для ручной фильтрации статусов
    const statusUnik = (entity as any).statusUnik || '';

    const nameKey = `name${i18n.language.toUpperCase()}` as keyof typeof entity;
    const rawName = entity[nameKey] as string;

    // Получаем перевод имени грешника
    const sinnerId = (entity.sinner || "").toLowerCase().replace(/\s/g, "");
    const translatedSinner = t(`sinners.${sinnerId}`);

    // Итоговая строка: [Название] Имя Грешника
    const fullDisplayName = `[${rawName}] ${translatedSinner}`;

    return (
        <>
            <SEOHelmet title={`${fullDisplayName} | Great Limbus Library`} description="" />
            <h1 className="entity-info-header">{fullDisplayName} <LanguageDisclaimer /></h1>
            <div className={"entityFullInfo"}>
                <EntityFullInfoEGO ego={entity} statusUnik={statusUnik} uptieValue={uptieValue}/>
                <EntityFullInfoSkillsEGO ego={entity} />
            </div>
        </>
    );
};