import React from 'react';
import { TooltipMobile } from '../../../tooltip-mobile/TooltipMobile';
import { setMobileModalTrigger } from '../../../../store/reducers/mobile-modal-reducer';
import { StatusesInterface } from '../../../../store/reducers/statuses-reducer';

export const useStatusHelpers = (
    dispatch: any, 
    i18n: any, 
    t: any, 
    statuses: StatusesInterface[], 
    historyContext: React.ReactNode[]
) => {
    const safeStatuses = statuses || [];

    const tagFunc = (statusId: string, resultLength: number, customText?: string) => {
        const status = safeStatuses.find((s) => s.id === statusId);
        // Если статус не найден, возвращаем исходный текст с решетками
        if (!status) return <span key={Math.random()}>{`#${statusId}#`}</span>;

        let name = i18n.language === "ru" ? (customText || status.nameRU) : status.nameEN;
        const descriptionStatus = i18n.language === "ru" ? status.descriptionRU : status.descriptionEN;
        const imgPath = `${process.env.PUBLIC_URL}/images/tags/${statusId}.webp`;

        const mobileModalHTML = (
            <TooltipMobile 
                image={<img className="status" src={imgPath} alt={statusId} />} 
                header={i18n.language === "ru" ? status.nameRU : status.nameEN} 
                text={descriptionStatus} 
                history={historyContext}
            />
        );

        let statusClass = status.tip === 'baf' ? 'status-name2' : status.tip === 'pas' ? 'status-name3' : 'status-name';

        return (
            <React.Fragment key={resultLength + Math.random()}>
                <img className="guide-status" src={imgPath} alt={statusId} style={{ width: "25px", height: "25px"}} />
                <span 
                    onClick={(e) => {
                        e.stopPropagation();
                        setMobileModalTrigger(dispatch, mobileModalHTML);
                    }} 
                    className={`${statusClass} status-name--${statusId} tooltip-container`}
                    style={{ cursor: 'pointer' }}
                >
                    {name}
                    <span className="entityFullInfo-tooltip">{t("SkillCoinDescription.clickToSeeDescription")}</span>
                </span>
            </React.Fragment>
        );
    };

    return { tagFunc };
};