import React from 'react';
import { useTranslation } from 'react-i18next';
import { useDispatch } from 'react-redux';
import { useQueryClient } from "react-query";

import { StatusesInterface } from '../../../store/reducers/statuses-reducer';
import { IdentityInterface } from '../../../store/reducers/ids-reducer';
import { EGOInterface } from '../../../store/reducers/ego-reducer';
import { MDGift } from '../../../store/reducers/md-gift-interface';

// Импорты хелперов
import { useEntityHelpers } from './Helps/SkillCoinEntityHelpers';
import { useStatusHelpers } from './Helps/SkillCoinStatusHelpers';
import { useGiftHelpers } from './Helps/SkillCoinGiftHelpers'; // НОВЫЙ ИМПОРТ

import "./SkillCoinDescription.css";
import "../../item-entity/ItemEntity.css";

export const romanNumerals: Record<string | number, string> = {
    6: 'EX', 5: 'V', 4: 'IV', 3: 'III', 2: 'II', 1: 'I'
};

interface ISkillCoinDescriptionProps {
    description: React.ReactNode;
    historyContext?: React.ReactNode[];
}

export const SkillCoinDescription: React.FC<ISkillCoinDescriptionProps> = ({ description, historyContext = [] }) => {
    const { t, i18n } = useTranslation();
    const dispatch = useDispatch();
    const queryClient = useQueryClient();
    const [isInitialLoading, setIsInitialLoading] = React.useState(true);

    React.useEffect(() => {
        // Искусственная задержка 500мс для подгрузки кэша
        const timer = setTimeout(() => {
            setIsInitialLoading(false);
        }, 500);
        return () => clearTimeout(timer);
    }, []);
    // Защита: добавляем || [], чтобы не падало, если кэш пуст
    const statuses = (queryClient.getQueryData('statuses') as StatusesInterface[]) || [];
    const ids = (queryClient.getQueryData('identities') as IdentityInterface[]) || [];
    const egos = (queryClient.getQueryData('ego') as EGOInterface[]) || [];
    const gifts = (queryClient.getQueryData("md-gifts") as MDGift[]) || [];

    // Инициализация разделенных хелперов
    const { newEntityLinkFunc, egoFunc } = useEntityHelpers(t, i18n, egos, ids);
    const { tagFunc } = useStatusHelpers(dispatch, i18n, t, statuses, historyContext);
    const { giftLinkFunc, simpleGiftFunc } = useGiftHelpers(dispatch, i18n, t, gifts, historyContext); // НОВЫЙ ХУК

    const redTextFunc = (value: string) => <span key={Math.random()} className="red-text">{value}</span>;
    const yellowUnderlinedFunc = (value: string) => <span key={Math.random()} style={{ color: '#f1d34d', textDecoration: 'underline' }}>{value}</span>;
    
    const coinFunc = (value: string, result: React.ReactNode[]) => {
        if (isNaN(+value)) return value;
        return (
            <React.Fragment key={result.length + Math.random()}>
                {!!result.length && <br />}
                <img className="coin" src={`${process.env.PUBLIC_URL}/images/general/coin${value}.webp`} alt="coin" />
            </React.Fragment>
        );
    };

    const weightFunc = (value: string) => {
        if (!value || value.trim() === "") return <span className="description-weight" key={Math.random()}>{t("SkillCoinDescription.weigth")}</span>;
        const [growth, max] = value.split(",");
        const hasGrowth = growth && growth.trim().length > 0;
        const numGrowth = hasGrowth ? +growth : null;
        return (
            <span className="description-weight" key={Math.random()}>
                {hasGrowth && (numGrowth! > 0 ? `+${numGrowth} ` : `${numGrowth} `)}
                {t("SkillCoinDescription.weigth")}
                {max ? ` (${t("SkillCoinDescription.max")} ${max})` : ""}
            </span>
        );
    };

    const conditionFunc = (value: string, result: React.ReactNode[], tracked: { lastCoinResultIndex: number }) => {
        const noBreak = value.endsWith('$');
        const cleanValue = noBreak ? value.slice(0, -1) : value;
        const key = cleanValue.toLowerCase().replace(/\s/g, ''); 
        const isCloseToCoin = tracked.lastCoinResultIndex !== -1 && tracked.lastCoinResultIndex === result.length - 1;
        const translatedLabel = t(`SkillCoinDescription.${key}`);
        const hasTranslation = translatedLabel !== `SkillCoinDescription.${key}`;

        return (
            <React.Fragment key={result.length + Math.random()}>
                {(!noBreak && !isCloseToCoin && !!result.length) && <br />}
                <span className={`condition condition--${key.substring(1, key.length - 1)}`}>
                    {hasTranslation ? translatedLabel : cleanValue} 
                </span>
            </React.Fragment>
        );
    };

    const processStContent = (content: string, resultLength: number) => {
        let tracked = { value: "", index: -1, lastCoinResultIndex: -1 };
        let res: React.ReactNode[] = [];
        const stSpecialsMap: Record<string, any> = { 
            "@": (v: any, r: any) => {
                // Защита от пустого значения @@
                if (!v || v.trim() === "") return <span key={Math.random()}>@@</span>;
                if (v.startsWith('gift_')) return simpleGiftFunc(v, r.length);
                tracked.lastCoinResultIndex = r.length;
                return coinFunc(v, r);
            }, 
            "$": (v: any, r: any) => conditionFunc(v, r, { lastCoinResultIndex: tracked.lastCoinResultIndex }), 
            "?": weightFunc, 
            "&": (v: any, r: any) => {
                let keyVal = ""; let numberVal = "";
                for (let char of v) {
                    if (isNaN(+char) && !["-", "+"].includes(char)) keyVal += char;
                    else if (char !== " ") numberVal += char;
                }
                return <span key={r.length + Math.random()} className={`coins-coditions coins-coditions--${keyVal.toLowerCase()}`}>{numberVal} {t(`SkillCoinDescription.${keyVal.toLowerCase()}`)}</span>;
            } 
        };

        for (let i = 0; i < content.length; i++) {
            const char = content[i];
            if (char in stSpecialsMap) {
                if (char === tracked.value) {
                    const val = content.substring(tracked.index + 1, i);
                    res.push(stSpecialsMap[char](val, res));
                    tracked = { ...tracked, value: "", index: i };
                } else {
                    const text = content.substring(tracked.index + 1, i);
                    if (tracked.value !== "@" && text !== "") res.push(<span key={res.length} dangerouslySetInnerHTML={{ __html: text.replaceAll("%", `<span class="perCent-special-font">%</span>`) }} />);
                    tracked = { ...tracked, value: char, index: i };
                }
            }
        }
        const remaining = content.substring(tracked.index + 1);
        if (remaining !== "") res.push(<span key={res.length} dangerouslySetInnerHTML={{ __html: remaining.replaceAll("%", `<span class="perCent-special-font">%</span>`) }} />);
        return <span className="st-content" key={`st-${resultLength}`}>{res}</span>;
    };

    const createDescriptionDangerousHTML = (str: React.ReactNode): React.ReactNode[] | React.ReactNode => {
        if (!str || typeof str !== 'string') return str;
        const regex = /(#[^#\s{}]+(?:\{[^}]*\})?#)|(&(?:ids|egos)_\d+&)|(&[^&]+&)|(@[^@]+@)|(~[^~]+~)|(<e>(.*?)<\/e>)|(\*\*\+\*\*|\*\*\-\*\*|\*\*\+\-\*\*)|(\^[^\^]+\^)|(✞[^✞]+✞)|(∞[^∞]+∞)|(\[disc\][^\[]*\[\])|(\?[^\?]*\?)|(\$[^\$]+\${1,2})|(©(\d):?([^©]*)©)/g;
        
        let result: React.ReactNode[] = [];
        let lastIndex = 0;
        let match: RegExpExecArray | null;
        let lastCoinResultIndex = -1;

        while ((match = regex.exec(str)) !== null) {
            if (match.index > lastIndex) {
                const plain = str.slice(lastIndex, match.index);
                result.push(<span key={`plain-${lastIndex}`} dangerouslySetInnerHTML={{ __html: plain.replaceAll("%", `<span class="perCent-special-font">%</span>`) }} />);
            }

            const [full, tag, entityLink, coinsCond, coin, link, , eInner, largeSymbol, red, yellow, , , weight, condition, goldFull, goldColor, goldContent] = match;

            if (tag) {
                const content = tag.slice(1, -1);
                // Разделяем логику для гифтов и статусов на уровне компонента-парсера
                if (content.startsWith('gift_')) {
                    result.push(giftLinkFunc(content));
                } else {
                    const statusMatch = content.match(/^([^{}]+)(?:\{([^}]*)\})?$/);
                    result.push(tagFunc(statusMatch?.[1] || content, result.length, statusMatch?.[2]));
                }
            }
            else if (coin) {
                const content = coin.slice(1, -1);
                // Защита от пустого тега @@
                if (!content || content.trim() === "") {
                    result.push(<span key={Math.random()}>@@</span>);
                } else if (content.startsWith('gift_')) {
                    result.push(simpleGiftFunc(content, result.length));
                } else { 
                    lastCoinResultIndex = result.length; 
                    result.push(coinFunc(content, result)); 
                }
            }
            else if (eInner) result.push(processStContent(eInner, result.length));
            else if (entityLink) result.push(newEntityLinkFunc(entityLink.slice(1, -1)));
            else if (coinsCond) {
                const val = coinsCond.slice(1, -1);
                if (val.startsWith('id_') || val.startsWith('ego_')) result.push(egoFunc(val));
                else {
                    let keyVal = ""; let numVal = "";
                    for (let char of val) { if (isNaN(+char) && !["-", "+"].includes(char)) keyVal += char; else if (char !== " ") numVal += char; }
                    result.push(<span key={result.length + Math.random()} className={`coins-coditions coins-coditions--${keyVal.toLowerCase()}`}>{numVal} {t(`SkillCoinDescription.${keyVal.toLowerCase()}`)}</span>);
                }
            }
            else if (largeSymbol) {
                const type = largeSymbol.includes('+-') ? 'plusminus' : largeSymbol.includes('+') ? 'plus' : 'minus';
                result.push(<span key={Math.random()} className={`large-symbol large-symbol--${type}`}>{largeSymbol.slice(2, -2)}</span>);
            }
            else if (red) result.push(redTextFunc(red.slice(1, -1)));
            else if (yellow) result.push(yellowUnderlinedFunc(yellow.slice(1, -1)));
            else if (weight) result.push(weightFunc(weight.slice(1, -1)));
            else if (condition) result.push(conditionFunc(condition.slice(1, -1), result, { lastCoinResultIndex }));
            else if (goldFull) {
                const innerParsed = createDescriptionDangerousHTML(goldContent);
                result.push(<span key={Math.random()} className={`gold-text-special gold-text--${goldColor}`}>{innerParsed}</span>);
            }

            lastIndex = regex.lastIndex;
        }

        if (lastIndex < str.length) {
            result.push(<span key={`rem-${lastIndex}`} dangerouslySetInnerHTML={{ __html: str.slice(lastIndex).replaceAll("%", `<span class="perCent-special-font">%</span>`) }} />);
        }
        return result;
    };

    return (
        <p className={`skill-coin-description`}>
            {createDescriptionDangerousHTML(description)}
        </p>
    );
};