import React, { useState, useEffect } from "react";
import { useTranslation } from "react-i18next";
import "./LoadingAnimation.css";

type TLoadingAnimationProps = {
  failureCount?: number;
};

export const LoadingAnimation: React.FC<TLoadingAnimationProps> = ({ failureCount = 0 }) => {
  const { t } = useTranslation();
  const [delayText, setDelayText] = useState("");
  const [isTooltipVisible, setIsTooltipVisible] = useState(false);

  useEffect(() => {
    // --- Логика авто-очистки через 8 секунд ---
    const autoRefreshTimeout = setTimeout(() => {
      console.warn("Loading takes too long. Clearing cache and refreshing...");
      localStorage.clear();
      sessionStorage.clear();
      // Добавляем timestamp, чтобы обойти кеш браузера на уровне запроса
      window.location.replace(window.location.origin + window.location.pathname + '?nocache=' + Date.now());
    }, 8000); 

    // --- Существующая логика текстов задержки ---
    let intervalId: NodeJS.Timeout;
    if (failureCount > 2) {
      const generateRandomDelayText = () => {
        const randomDelay = Math.floor(Math.random() * 14) + 1;
        setDelayText(t(`LoadingAnimation.delay${randomDelay}`));
      };

      generateRandomDelayText();
      intervalId = setInterval(generateRandomDelayText, 10000);
    }

    // Очистка таймеров при размонтировании
    return () => {
      clearTimeout(autoRefreshTimeout);
      if (intervalId) clearInterval(intervalId);
    };
  }, [failureCount, t]);

  // Остальной JSX остается без изменений...
  const handleMouseOver = () => setIsTooltipVisible(true);
  const handleMouseOut = () => setIsTooltipVisible(false);

  return (
    <div className="loading-container">
      <div className="image-container">
        <img 
          src="/images/general/loading.webp" 
          alt="Loading Animation" 
          className="loading-image" 
          onMouseOver={handleMouseOver} 
          onMouseOut={handleMouseOut} 
        />
        {isTooltipVisible && (
          <div className="tooltip">{t("LoadingAnimation.tooltip")}</div>
        )}
      </div>
      <div className="loading">
        {t("LoadingAnimation.text")}
        <span className="dot">.</span>
        <span className="dot">.</span>
        <span className="dot">.</span>
      </div>
      <span className="delay-info">{failureCount > 2 && delayText}</span>
    </div>
  );
};