import { useQuery, QueryClient } from "react-query";
import { SUPABASE_URL, SUPABASE_ANON_KEY } from "../tools/supabaseClient";

const CACHE_KEY = 'news_list_cache';
const CACHE_TIME = 15 * 60 * 1000; 

// 1. Управляем кэшем (копия твоей логики)
const getDataFromCache = () => {
  if (typeof window === 'undefined') return null;
  const cachedData = localStorage.getItem(CACHE_KEY);
  if (cachedData) {
    const { data, timestamp } = JSON.parse(cachedData);
    if (Date.now() - timestamp < CACHE_TIME) {
      return data;
    }
  }
  return null;
};

const setDataToCache = (data: any) => {
  const cacheData = {
    data,
    timestamp: Date.now(),
  };
  localStorage.setItem(CACHE_KEY, JSON.stringify(cacheData));
};

// 2. Экшен запроса к Supabase
const useFetchNewsListAction = async () => {
  const cached = getDataFromCache();
  if (cached) return cached;

  // Стучимся в таблицу news_list
  const endpoint = '/rest/v1/news_list?select=*';
  const url = `${SUPABASE_URL}${endpoint}&apikey=${SUPABASE_ANON_KEY}`;

  const response = await fetch(url, {
    method: 'GET',
    headers: {
      'Content-Type': 'application/json',
    }
  });

  if (!response.ok) {
    throw new Error(`Ошибка Supabase News: ${response.status}`);
  }

  const data = await response.json();
  setDataToCache(data);
  return data;
};

// 3. Основной хук для компонентов
export const useFetchNewsList = () => {
  return useQuery("news_list", useFetchNewsListAction, {
    staleTime: CACHE_TIME,
    cacheTime: Infinity,
    refetchOnWindowFocus: false,
    retry: 5,
    retryDelay: (attempt) =>
        Math.min(attempt > 1 ? 2 ** attempt * 1000 : 1000, 30 * 1000),
    onError: (error) => {
      console.error("Error fetching News from Supabase:", error);
    },
  });
};

// 4. Client для React Query (инициализация)
export const createQueryClient = () => {
  const queryClient = new QueryClient({
    defaultOptions: {
      queries: {
        staleTime: CACHE_TIME,
        cacheTime: Infinity,
      },
    },
  });

  if (typeof window !== 'undefined') {
    const cachedData = getDataFromCache();
    if (cachedData) {
      queryClient.setQueryData("news_list", cachedData);
    }
  }

  return queryClient;
}