import React from "react";
import { sinTypes } from "../../constants/skillBasedTypes";
import { EGOInterface } from "../../store/reducers/ego-reducer";
import "./ItemEGOInfo.css";

interface ItemEGOInfoInterface {
    entity: EGOInterface;
}

export const ItemEGOInfo: React.FC<ItemEGOInfoInterface> = ({ entity }) => {
    const { egoTier, sanity, dmgType, egoSin, season } = entity;

    // --- ЛОГИКА ПЛАШЕК (АНАЛОГ IDENTITY) ---
    const seasonArray = Array.isArray(season) ? season : [season];

    const isWalpurgis = seasonArray.some(s => s?.includes("w-"));
    const isEvent = seasonArray.some(s => s?.startsWith("i-"));
    const seasonTag = seasonArray.find(s => s?.startsWith("s-"));
    const seasonNumber = seasonTag ? seasonTag.split("-")[1] : null;

    return (
        <div className="item-ego-info-container">
            {/* Контент */}
            <div className="item-ego-info-content">
                <div className="item-ego-info-skills">
                    <div className="item-ego-info-sin">
                        <img
                            src={`${process.env.PUBLIC_URL}/images/general/sanity.webp`}
                            alt="sanity"
                        />
                        {sanity[0]}
                    </div>

                    {dmgType.map((dt, index) => (
                        <div key={index} className="item-ego-info-sin">
                            <img
                                src={`${process.env.PUBLIC_URL}/images/dmg-type/${dt}.webp`}
                                alt={dt}
                            />
                            <div className={`item-ego-info-line ${egoSin}-sin-color`} />
                        </div>
                    ))}
                </div>

                <div className="item-ego-info-skills">
                    {sinTypes.map((sin) => {
                        if (!entity[sin]) return null;
                        return (
                            <div key={sin} className="item-ego-info-sin">
                                <img
                                    src={`${process.env.PUBLIC_URL}/images/sins/${sin}.webp`}
                                    alt={sin}
                                />
                                {"x" + entity[sin]}
                                <div
                                    className={`item-ego-info-line ${sin}-sin-color`}
                                />
                            </div>
                        );
                    })}
                </div>

                <span
                    className={[
                        "item-ego-info-tier-rank",
                        `item-ego-info-tier-rank--${egoTier}`,
                    ].join(" ")}
                >
                    {egoTier}
                </span>
            </div>

            <div className="item-identity-info-badges">
                {seasonNumber && (
                    <div 
                        className="info-badge season-badge" 
                        /* Теперь передаем цвет только для нижней полоски */
                        style={{ "--badge-line-color": `var(--season-s-${seasonNumber}-color)` } as React.CSSProperties}
                    >
                        S{seasonNumber}
                    </div>
                )}
                {isEvent && (
                    <div className="info-badge event-badge">
                        E
                    </div>
                )}
                {isWalpurgis && (
                    <div className="info-badge walpurgis-badge">
                        W
                    </div>
                )}
            </div>

            <div className="item-ego-info-arrow" />
        </div>
    );
};
