import React from "react";
import { useTranslation } from "react-i18next";
import { dmgType, guardType, guardTypeExtended, sinType, normalizeGuardType } from "../../constants/types";
import { IdentityInterface } from "../../store/reducers/ids-reducer";
import "./ItemIdentityInfo.css";

interface ItemIdentityInfoInterface {
    entity: IdentityInterface;
}
type Tskill = {
    imageUrl: string,
    type: dmgType | guardType,
    count: number,
    sin: sinType
}

export const ItemIdentityInfo: React.FC<ItemIdentityInfoInterface> = ({ entity }) => {
    const { guardType, idTier, guardSin, countPassive1, countPassive2, sinPassive1, sinPassive2, skillsDmgType, skillsSin, season } = entity;
    const { t } = useTranslation();

    // --- ЛОГИКА ПЛАШЕК ---
    const seasonArray = Array.isArray(season) ? season : [season];
    const isWalpurgis = seasonArray.some(s => s?.includes("w-"));
    const isEvent = seasonArray.some(s => s?.startsWith("i-"));
    const seasonTag = seasonArray.find(s => s?.startsWith("s-"));
    const seasonNumber = seasonTag ? seasonTag.split("-")[1] : null;

    const setupSkills = (): Tskill[] => {
        const counts = [3, 2, 1];
        const result: Tskill[] = [];
        const minLength = Math.min(skillsDmgType.length, skillsSin.length);
        for (let i = 0; i < minLength; i++) {
            const curr = {
                imageUrl: `dmg-type/${skillsDmgType[i]}`,
                type: skillsDmgType[i],
                count: counts[i] || 0,
                sin: skillsSin[i]
            };
            result.push(curr);
        }
        return result;
    };

    const skills: Tskill[] = [
        ...setupSkills(),
        ...guardType.map((type, i) => ({
            imageUrl: `guard-type/${(type as guardTypeExtended).replace("|", ";")}`,
            type: normalizeGuardType(type),
            count: 1,
            sin: guardSin[i]
        })),
    ];

    const passives = [
        {
            imageUrl: sinPassive1.map(sin => `sins/${sin}`),
            count: countPassive1,
            description: t("ItemIdentityInfo.battlePassive")
        },
        {
            imageUrl: sinPassive2.map(sin => `sins/${sin}`),
            count: countPassive2,
            description: t("ItemIdentityInfo.supportPassive")
        },
    ];

    return (
        <div className={`item-identity-info-container `} >
            <div className="item-identity-info-content">
                <div className={"item-identity-info-skills"}>
                    {skills.map(({ imageUrl, sin }) => {
                        return (
                            <div key={`skill${Math.random()}`} className="item-identity-info-sin">
                                <img src={`${process.env.PUBLIC_URL}/images/${imageUrl}.webp`} alt={imageUrl} />
                                <div className={["item-identity-info-line", `${sin}-sin-color`].join(" ")}></div>
                            </div>
                        )
                    })}
                </div>
                <div className={"item-identity-info-tiers"}>
                    {
                        passives.map(({ imageUrl, count, description }, index) => {
                            return (
                                <div key={`${index}`} className="item-identity-info-tier">
                                    {imageUrl.map((url, i) => (
                                        <div key={i} className="item-identity-info-tier-description">
                                            <img src={`${process.env.PUBLIC_URL}/images/${url}.webp`} alt={url} />
                                            {count[i] > 0 && <span>{`x${count[i]}`}</span>}
                                        </div>
                                    ))}
                                    <div className="item-identity-info-tier-rank-container">
                                        <span >{description}</span>
                                    </div>
                                </div>
                            )
                        })
                    }
                </div>
                <span className={["item-identity-info-tier-rankID", `item-identity-info-tier-rank--${idTier}`].join(" ")} >{idTier}</span>
            </div>

           <div className="item-identity-info-badges">
            {seasonNumber && (
                <div 
                    className="info-badge season-badge" 
                    /* Теперь передаем цвет только для нижней полоски */
                    style={{ "--badge-line-color": `var(--season-s-${seasonNumber}-color)` } as React.CSSProperties}
                >
                    S{seasonNumber}
                </div>
            )}
            {isEvent && (
                <div className="info-badge event-badge">
                    E
                </div>
            )}
            {isWalpurgis && (
                <div className="info-badge walpurgis-badge">
                    W
                </div>
            )}
        </div>

            <div className={"item-identity-info-arrow"} />
        </div>
    )
}