import React from "react";
import { useParams } from "react-router-dom";
import { useTranslation } from "react-i18next";
import "./GuidePageFull.css";
import "../../entity-full-info/entity-full-info-ego/EntityFullInfoEGO.css"
import { SkillCoinDescription } from "../text-formatter/SkillCoinDescription";
import "../../main-info/NavigationSection/NavigationSection.css"
import { GuideInterface } from "../../../store/reducers/guides-reducer";
import { GuideTagInterface } from "../../../store/reducers/guides-tags-reducer";
import { useQueryClient } from 'react-query';
import { SEOHelmet } from '../../../pages/SEOHelmet';

// ТВОИ ТЕГИ НАПРЯМУЮ В КОДЕ
const HARDCODED_TAGS: GuideTagInterface[] = [
    { Id: "eventGuide", nameRu: "Путеводитель по Событию", nameEn: "Event Guide" },
    { Id: "forBeginners", nameRu: "Для Новичков", nameEn: "For Beginners" },
    { Id: "refractionRailway", nameRu: "Ж/Д Преломления", nameEn: "The Refraction Railway" }
];

export { SkillCoinDescription };

const formatDateFromISO = (dateString: string | number): string => {
    let newDate: Date;

    if (typeof dateString === 'string') {
        newDate = new Date(dateString);
    } else if (typeof dateString === 'number') {
        const excelStartDate = new Date(1899, 11, 30);
        const millisecondsPerDay = 24 * 60 * 60 * 1000;
        newDate = new Date(excelStartDate.getTime() + dateString * millisecondsPerDay);
    } else {
        return '';
    }

    if (isNaN(newDate.getTime())) return '';

    const month = String(newDate.getMonth() + 1).padStart(2, '0');
    const day = String(newDate.getDate()).padStart(2, '0');
    return `${day}.${month}.${newDate.getFullYear()}`;
};

const combineDescriptions = (guide: GuideInterface, language: string): string => {
    const descriptionParts: string[] = [];
    const baseKey = language === "ru" ? "descriptionRu" : "descriptionEn";
    
    let partNumber = 1;
    while (true) {
        const key = `${baseKey}${partNumber}`;
        const content = guide[key as keyof GuideInterface];
        if (content) {
            descriptionParts.push(content as string);
            partNumber++;
        } else {
            break;
        }
    }
    
    return descriptionParts.join("");
};

export const GuidePageFull: React.FC = () => {
    const { guideId } = useParams();
    const queryClient = useQueryClient();
    const { i18n } = useTranslation();

    const guides = queryClient.getQueryData('guides') as GuideInterface[];
    
    // Используем хардкод вместо queryClient
    const tags = HARDCODED_TAGS;
    
    const guide = guides?.find((g: GuideInterface) => g.ids === guideId);

    if (!guide) {
        return <div className="guide-not-found">Guide not found</div>;
    }

    const name = (i18n.language === "ru") ? guide.nameRu : guide.nameEn;

    const rawDescription = combineDescriptions(guide, i18n.language);
    const fixedDescription = rawDescription
        .replace(/imagesguides/g, "/images/guides/")
        .replace(/(guide_\d+)([a-zA-Z])/g, "$1/$2")
        .replace(/\[img:([^/][^\]]+)\]/g, "[img:/$1]");

    // Чистим ID тегов от пробелов и сопоставляем с хардкодом
    const guideTagsIds: string[] = guide.tagsId ? guide.tagsId.split(',').map((id: string) => id.trim()) : [];
    const guideTags = tags.filter((tag: GuideTagInterface) => guideTagsIds.includes(tag.Id));

    return (
        <>
            <SEOHelmet title={`${name} | Great Limbus Library`} description=""/>
            <div className="guide-page">
                <h1 className="guide-page-title">{name}</h1>
                <div className="guide-header">
                    <time className="guide-page-date">
                        {(i18n.language === 'ru') ? 'Последнее изменение' : 'Last updated on'}: {formatDateFromISO(guide.date)}
                    </time>
                    <div className="guide-tags-container">
                        <span className="tags-title">{(i18n.language === 'ru') ? 'Список всех тегов' : 'List of all tags'}: </span>
                        {guideTags.map((tag: GuideTagInterface) => (
                            <span key={tag.Id} className="dropdown-tag-item">
                                {(i18n.language === 'ru') ? tag.nameRu : tag.nameEn}
                            </span>
                        ))}
                    </div>
                </div>

                <div className="guide-page-content">
                    <SkillCoinDescription description={fixedDescription} />
                </div>
            </div>
        </>
    );
};