import { useQuery, QueryClient } from "react-query";
import { SUPABASE_URL, SUPABASE_ANON_KEY } from "../tools/supabaseClient";
import { md_eventsKeys } from "../constants/md-eventsKeys";

const CACHE_KEY = 'md-events_cache';
const CACHE_TIME = 15 * 60 * 1000; // 15 минут

const getDataFromCache = () => {
  if (typeof window === 'undefined') return null;
  const cachedData = localStorage.getItem(CACHE_KEY);
  if (cachedData) {
    const { data, timestamp } = JSON.parse(cachedData);
    if (Date.now() - timestamp < CACHE_TIME) return data;
  }
  return null;
};

const setDataToCache = (data: any) => {
  localStorage.setItem(CACHE_KEY, JSON.stringify({ data, timestamp: Date.now() }));
};

const useFetchMDEventsAction = async () => {
  const cached = getDataFromCache();
  if (cached) return cached;

  const url = `${SUPABASE_URL}/rest/v1/md_events?select=*&order=order.asc&apikey=${SUPABASE_ANON_KEY}`;
  const response = await fetch(url);
  if (!response.ok) throw new Error("Ошибка загрузки MD Events");

  const rawData = await response.json();

  const validatedData = rawData.map((row: any) => {
    // 1. Сначала прогоняем через стандартные валидаторы
    const item: any = {};
    md_eventsKeys.forEach(({ key, validation }) => {
      const rawValue = row[key] !== undefined ? row[key] : row[key.toLowerCase()];
      const { validatedVal } = validation(rawValue ?? (key.includes('choice') ? "{}" : ""));
      item[key] = validatedVal;
    });

    // 2. ФИКС СТРУКТУРЫ: Если choiceEN/RU пришли как "плоские" объекты из БД, 
    // убеждаемся, что внутри есть gift_id и options, иначе создаем их
    const fixChoice = (choice: any) => {
      if (!choice || typeof choice !== 'object') return { gift_id: [], options: {} };
      return {
        // Если gift_id уже есть внутри choice - берем его, иначе ищем в корне строки
        gift_id: choice.gift_id || item.gift_id || [],
        options: choice.options || item.options || {}
      };
    };

    item.choiceEN = fixChoice(item.choiceEN);
    item.choiceRU = fixChoice(item.choiceRU);

    return item;
  });

  setDataToCache(validatedData);
  return validatedData;
};

export const useFetchMDEvents = () => {
  return useQuery("md-events", useFetchMDEventsAction, {
    staleTime: CACHE_TIME,
    cacheTime: Infinity,
    refetchOnWindowFocus: false,
    retry: 5,
    onError: (error) => {
      console.error("Error fetching md-events from Supabase:", error);
    },
  });
};

export const createQueryClient = () => {
  const queryClient = new QueryClient({
    defaultOptions: { queries: { staleTime: CACHE_TIME, cacheTime: Infinity } },
  });

  if (typeof window !== 'undefined') {
    const cachedData = getDataFromCache();
    if (cachedData) {
      queryClient.setQueryData("md-events", cachedData);
    }
  }
  return queryClient;
};