import React, { useState, useEffect } from 'react';
import { IdentityInterface } from '../../../../store/reducers/ids-reducer';
import { ISkill } from '../EntityFullInfoSkills';
import "./EntityFullInfoSkill.css"
import { SkillCoinDescription } from "../../../guides/text-formatter/SkillCoinDescription";
import { getAtackWeightBonusFromDescription, cleanDescriptionFromInfinityTags } from '../../../../tools/getAtackWeightBonusFromDescription';
import { getUnbreakableCoinBonusFromDescription } from '../../../../tools/getUnbreakableCoinBonusFromDescription';
import { useTranslation } from 'react-i18next';
import { useDispatch } from 'react-redux';
import { setMobileModalTrigger } from '../../../../store/reducers/mobile-modal-reducer';
import { TooltipMobile } from '../../../tooltip-mobile/TooltipMobile'; 
import { mobileLayoutFrom } from '../../../../constants/mobileLayoutFrom';
import { useTypedSelector } from '../../../../hooks/useTypedSelector';
import { setSelectedUptie } from '../../../../store/reducers/uptie-reducer';

interface IEntityFullInfoProps {
    identity: IdentityInterface;
    skill: ISkill;
    maxLvlIdentity: number;
   
}

export const EntityFullInfoSkill: React.FC<IEntityFullInfoProps> = ({ identity, skill, maxLvlIdentity }) => {
    const { imgUrl, countCoin, weightCoin, damage, maxPossibleDmg, minPossibleDmg, skillsOrder, guardTier } = identity;
    const { t, i18n } = useTranslation();
    const { selectedUptie } = useTypedSelector(s => s.uptieReducer);
    const dispatch = useDispatch();

    // Безопасная проверка для nameSkill
    const nameSkillKey = `nameSkill${i18n.language.toUpperCase()}` as keyof IdentityInterface;
    const nameSkill = Array.isArray(identity[nameSkillKey]) ? identity[nameSkillKey] as string[] : [];

    // Проверка на корректность индекса
    const skillIndexValid = skill.index >= 0 && skill.index < nameSkill.length;

    const [tooltipVisible, setTooltipVisible] = useState(false);


    const handleMouseEnter = () => {
        if (skillIndexValid && nameSkill[skill.index].length > 20) {
            setTooltipVisible(true);
        }
    };

    const handleMouseLeave = () => {
        setTooltipVisible(false);
    };

    const descriptionCoinKeyStr = `descriptionCoin${i18n.language.toUpperCase()}${selectedUptie}`;
    const descriptionCoinKey = descriptionCoinKeyStr as keyof IdentityInterface;
    const descriptionCoinRaw = typeof identity[descriptionCoinKey] === 'string' ? identity[descriptionCoinKey] as string : "";

    let skillDescriptionPart = "";
    if (descriptionCoinRaw.includes("|")) {
        const parts = descriptionCoinRaw.split("|");
        skillDescriptionPart = (skill.index >= 0 && skill.index < parts.length) ? parts[skill.index] : "";
    }

    const testDescription = cleanDescriptionFromInfinityTags(skillDescriptionPart);

    // Безопасный доступ к countCoin
    const countCoinVal = Array.isArray(countCoin) && skill.index >= 0 && skill.index < countCoin.length ? countCoin[skill.index] : 0;

    const coins = new Array(countCoinVal).fill(0);

    const passiveKeyStr = `descriptionPassive1${i18n.language.toUpperCase()}`;
    const passiveKey = passiveKeyStr as keyof IdentityInterface;
    const passiveDescription = typeof identity[passiveKey] === 'string' ? identity[passiveKey] as string : "";
    const attackWeightBuff = getAtackWeightBonusFromDescription([testDescription, passiveDescription]);
    const unbreakableCoinBuff = getUnbreakableCoinBonusFromDescription(testDescription, countCoinVal);

    const damageOrGuardType = ((skill.index === 3 && skill.type === `guard`) || (skill.index === 4 && skill.type === `guard`))
        ? t("EntityFullInfoSkill.guardType") : t("EntityFullInfoSkill.damageType");

    const [beforeKey, afterKey] = skill.skillType ? skill.skillType.split('|').map(s => s.trim()) : ["", ""];

    const damageOrGuardTypeImgHTML = beforeKey
        ? <img src={`${process.env.PUBLIC_URL}/images/guard-type/${beforeKey}.webp`} alt={`${beforeKey}`} />
        : null;

    const guardDamageType = t("EntityFullInfoSkill.damageType");
    const guardDamageTypeImgHTML = afterKey
        ? <img src={`${process.env.PUBLIC_URL}/images/general/${afterKey}.webp`} alt={`${afterKey}`} />
        : null;

    const sinType = t("EntityFullInfoSkill.sin");
    const sinTypeImgHTML = skill.sin
        ? <img src={`${process.env.PUBLIC_URL}/images/sins/${skill.sin}.webp`} alt={`${skill.sin}`} />
        : null;

    const selectedUptieIndex = selectedUptie - 1;

    const safeArrayAccess = (arr: any, outerIndex: number, innerIndex: number): any => {
        if (Array.isArray(arr) && outerIndex >= 0 && outerIndex < arr.length) {
            const innerArray = arr[outerIndex];
            if (Array.isArray(innerArray) && innerIndex >= 0 && innerIndex < innerArray.length) {
                return innerArray[innerIndex];
            }
        }
        return 0;
    };

    const basicCoinValue = safeArrayAccess(identity.basicCoin, selectedUptieIndex, skill.index);
    const growthPerCoinValue = safeArrayAccess(identity.growthPerCoin, selectedUptieIndex, skill.index);
    const maxCoinValueValue = safeArrayAccess(identity.maxCoinValue, selectedUptieIndex, skill.index);
    const fullMaxCoinValueValue = safeArrayAccess(identity.fullMaxCoinValue, selectedUptieIndex, skill.index);

    const maxCoinBaseValue = Math.sign(growthPerCoinValue) === -1 ? basicCoinValue : basicCoinValue + growthPerCoinValue * countCoinVal;

    const maxCoinTooltip = t("EntityFullInfoSkill.maxCoin");
    const maxCoinImgHTML = <img src={`${process.env.PUBLIC_URL}/images/general/coinBefore.webp`} alt={`${imgUrl}`} />;
    const maxCoinWithConditionTooltip = t("EntityFullInfoSkill.coinCondition");
    const maxCoinWithConditionImgHTML = <img src={`${process.env.PUBLIC_URL}/images/general/coinCondition.webp`} alt={`max coin with condition`} />;
    const attackDefLevelValue = maxLvlIdentity + (damage && Array.isArray(damage) && damage[skill.index] ? damage[skill.index] : 0);
    const attackDefLevelTooltip = ((skill.index === 3 && skill.type === `guard`) || (skill.index === 4 && skill.type === `guard`))
        ? t("EntityFullInfoSkill.defenseLevel") : t("EntityFullInfoSkill.offenseLevel");

    const attackDefLevelImgHTML = <img src={`${process.env.PUBLIC_URL}/images/general/${((skill.index !== 3 && skill.type !== `guard`) || (skill.index !== 4 && skill.type !== `guard`)) ? `damage` : `evadeDef1`}.webp`} alt={`attack/defense level`} />;

    const minPossibleDmgValue = (minPossibleDmg && Array.isArray(minPossibleDmg) && minPossibleDmg[skill.index]) || 0;
    const minPossibleDmgTooltip = t("EntityFullInfoSkill.minPotencial");
    const minPossibleDmgImgHTML = <img src={`${process.env.PUBLIC_URL}/images/general/damageMin.webp`} alt={`damageMin`} />;

    const maxPossibleDmgValue = (maxPossibleDmg && Array.isArray(maxPossibleDmg) && maxPossibleDmg[skill.index]) || 0;
    const maxPossibleDmgTooltip = t("EntityFullInfoSkill.maxPotencial");
    const maxPossibleDmgImgHTML = <img src={`${process.env.PUBLIC_URL}/images/general/maximumDamage.webp`} alt={`damageMax`} />;

    const atkSkillsOrderValue = skillsOrder && skillsOrder[skill.index]
    ? skillsOrder[skill.index].match(/\d+(\.\d+)?/)?.[0] // Ищем числа с optional decimal part
    : undefined;
    const defSkillsOrderValue = skillsOrder && skillsOrder[skill.index]
        ? skillsOrder[skill.index].match(/\d+/)?.[0]
        : undefined;


    // Оптимизированная функция для проверки блокировки
    const getShowLock = () => {
        const isUptie1Or2 = selectedUptie === 1 || selectedUptie === 2;
        
        // Если это id_155 и skillsOrder[skill.index] включает "s-3.2" - никогда не блокируем
        if (imgUrl === "id_155" && skillsOrder && skillsOrder[skill.index]?.includes("s-3.2")) {
            return false;
        }
        
        // Исключение для id_148 - "d-2" открывается на 2 аптайе
        if (imgUrl === "id_148" && skillsOrder && skillsOrder[skill.index]?.includes("d-2")) {
            return selectedUptie === 1; // Только на 1 аптайе заблокировано
        }
        
        // Общие правила для стандартного skillsOrder
        if (skillsOrder && skillsOrder[skill.index] === "standard" && skill.index === 3) {
            return isUptie1Or2;
        }
        
        // Правила для уникальных skillsOrder
        if (skillsOrder && skillsOrder[skill.index]) {
            const skillOrder = skillsOrder[skill.index];
            
            // Для s-3.1, s-3.2, s-3.3 блокируем на 1 и 2 аптайе
            // (для id_155 s-3.2 уже обработан выше)
            if (skillOrder.includes("s-3.1") || skillOrder.includes("s-3.2") || skillOrder.includes("s-3.3")) {
                return isUptie1Or2;
            }
            
        
        }
        
        // Специфичные проверки для отдельных ID
        const specialCases = [
            // id_125, id_112 и т.д. - блокировка 3 скилла на 1-2 аптай
            { ids: ["id_125", "id_112", "id_128", "id_113", "id_122", "id_101"], skillIndex: 3, upties: [1, 2] },
            // id_124 - блокировка 5 скилла на 1-2 аптай
            { ids: ["id_124"], skillIndex: 5, upties: [1, 2] },
            // id_152 - блокировка 5 скилла на 1-2 аптай
            { ids: ["id_152"], skillIndex: 5, upties: [1, 2] },
            // id_126 - блокировка 4 и 5 скиллов на 1-2 аптай
            { ids: ["id_126"], skillIndex: [4, 5], upties: [1, 2] }
        ];
        
        for (const specialCase of specialCases) {
            const isIdMatch = specialCase.ids.includes(imgUrl);
            const isSkillMatch = Array.isArray(specialCase.skillIndex) 
                ? specialCase.skillIndex.includes(skill.index)
                : skill.index === specialCase.skillIndex;
            const isUptieMatch = specialCase.upties.includes(selectedUptie);
            
            if (isIdMatch && isSkillMatch && isUptieMatch) {
                return true;
            }
        }
        
        // Для skill.index === 2 на 1-2 аптай (если нужно - раскомментировать)
        if (skill.index === 2 && isUptie1Or2) {
           return true;
        }
        
        return false;
    };

    const showLock = getShowLock();


    const handleMobileTooltipClick = (tooltip: React.ReactNode) => {
        if (window.innerWidth > mobileLayoutFrom) return;
        setMobileModalTrigger(
            dispatch,
            tooltip
        );
    };

    return (
        <article className={`${'entityFullInfo-skill'}`} >
            <span className={`${'entityFullInfo-skill-index'}`} >
                {
                    (atkSkillsOrderValue && defSkillsOrderValue)
                        ?
                        (skill.type === "attack")
                            ? `${t("EntityFullInfoSkill.skill")} ${atkSkillsOrderValue}`
                            : skill.type[4] !== `attack` && skill.type[5] !== `attack`
                                ? (identity.guardType && identity.guardType.length === 1
                                    ? t("EntityFullInfoSkill.defSkill")
                                    : `${t("EntityFullInfoSkill.defSkill")} ${defSkillsOrderValue}`)
                                : t("EntityFullInfoSkill.defSkill")
                        :
                        (skill.type === "attack")
                            ? `${t("EntityFullInfoSkill.skill")} ${skill.index + 1}`
                            : skill.type[4] !== `attack` && skill.type[5] !== `attack`
                                ? (identity.guardType && identity.guardType.length === 1
                                    ? t("EntityFullInfoSkill.defSkill")
                                    : `${t("EntityFullInfoSkill.defSkill")} ${skill.index + 1 - (identity.skillsDmgType ? identity.skillsDmgType.length : 0)}`)
                                : t("EntityFullInfoSkill.defSkill")
                }
            </span>

            <div className={`${'entityFullInfo-skill-r'}`}>
                {(showLock) && (
                    <div className="lock-overlay">

                        <div className="lock-center">
                            <img src="/images/general/lock.png" alt="Lock Center" />
                        </div>

                    </div>
                )}

                <div style={{ display: "flex", flexWrap: "wrap", alignItems: "center", gap: "20px", marginBottom: "15px", position: "relative" }}>
                    <p
                        className={`skill-name ${
                            (skill.type === 'guard' && selectedUptie < Number(guardTier) && !(imgUrl === "id_126" && skill.index === 7))
                                ? 'no-sin-color'
                                : `${skill.sin}-sin-color`
                        }`}
                        onMouseEnter={handleMouseEnter}
                        onMouseLeave={handleMouseLeave}
                    >
                        {skillIndexValid
                            ? (nameSkill[skill.index].length > 30 ? `${nameSkill[skill.index].substring(0, 30)}...` : nameSkill[skill.index])
                            : ""}
                    </p>
                    {tooltipVisible && skillIndexValid && (
                        <div className="tooltip">
                            {nameSkill[skill.index]}
                        </div>
                    )}
                    <span onClick={
                        () => {
                            handleMobileTooltipClick(<TooltipMobile
                                text={t("EntityFullInfoSkill.count")}
                                header={skill.resourceCount !== undefined ? `x${skill.resourceCount}` : ""}
                            />
                            )
                        }}
                        className={`${'skill-count'} tooltip-container`} >
                        {skill.resourceCount !== 0 ? `x${skill.resourceCount}` : ""}
                        <span className={`${'entityFullInfo-tooltip'}`} >{t("EntityFullInfoSkill.count")} </span>
                    </span>
                    <span onClick={
                        () => {
                            handleMobileTooltipClick(<TooltipMobile
                                text={t("EntityFullInfoSkill.baseValue")}
                                header={`${basicCoinValue}`}
                            />
                            )
                        }}
                        className={`${'skill-baseCoin'} tooltip-container coin-text`} >{basicCoinValue}
                        <span className={`${'entityFullInfo-tooltip'}`} >{t("EntityFullInfoSkill.baseValue")} </span>
                    </span>
                    <div className='entityFullInfo-coins' >
                        <span onClick={
                            () => {
                                handleMobileTooltipClick(<TooltipMobile
                                    text={t("EntityFullInfoSkill.coinGain")}
                                    header={`${growthPerCoinValue}`}
                                />
                                )
                            }}
                            className={`${'skill-coinGrowth'} tooltip-container`} >{Math.sign(growthPerCoinValue) === -1 ? "" : "+"}{growthPerCoinValue}
                            <span className={`${'entityFullInfo-tooltip'}`} >{t("EntityFullInfoSkill.coinGain")} </span>
                        </span>
                        {
                            coins.map(
                                (element, index) => {
                                    return (!unbreakableCoinBuff[index]) ? <img key={index} src={`${process.env.PUBLIC_URL}/images/general/coin.webp`} alt={`coin`} /> : <img key={index} src={`${process.env.PUBLIC_URL}/images/general/unbreakableCoin.webp`} alt={`unbreakableCoin`} />;
                                }
                            )
                        }
                    </div>
                </div>

                <div style={{ display: "flex", flexWrap: "wrap", alignItems: "center", gap: "20px", marginBottom: "15px" }}>

                    <div onClick={
                        () => {
                            handleMobileTooltipClick(<TooltipMobile
                                image={damageOrGuardTypeImgHTML}
                                text={damageOrGuardType}
                            />
                            )
                        }
                    }
                        className={`${'skill-atk'} tooltip-container`} >
                        {damageOrGuardTypeImgHTML}
                        <span className={`${'entityFullInfo-tooltip'}`} >{damageOrGuardType}</span>
                    </div>
                    {
                        (guardDamageTypeImgHTML) ? <div onClick={
                            () => {
                                handleMobileTooltipClick(<TooltipMobile
                                    image={guardDamageTypeImgHTML}
                                    text={guardDamageType}
                                />
                                )
                            }
                        }
                            className={`${'skill-atk'} tooltip-container`} >
                            {guardDamageTypeImgHTML}
                            <span className={`${'entityFullInfo-tooltip'}`} >{guardDamageType}</span>
                        </div>
                            : <></>
                    }

                    {!(skill.type === 'guard' && selectedUptie < Number(guardTier)) && sinTypeImgHTML && (
                        <div onClick={
                            () => {
                                handleMobileTooltipClick(<TooltipMobile
                                    image={sinTypeImgHTML}
                                    text={sinType}
                                />
                                )
                            }
                        }
                            className={`${'skill-atk'} tooltip-container`} >
                            {sinTypeImgHTML}
                            <span className={`${'entityFullInfo-tooltip'}`} >{sinType} </span>
                        </div>
                    )}
                    <div onClick={
                        () => {
                            handleMobileTooltipClick(<TooltipMobile
                                image={maxCoinImgHTML}
                                text={maxCoinTooltip}
                                header={`${maxCoinBaseValue}`}
                            />
                            )
                        }
                    }
                        className={`${'skill-atk'} tooltip-container`} >
                        {maxCoinBaseValue}
                        {maxCoinImgHTML}
                        <span className={`${'entityFullInfo-tooltip'}`} >{maxCoinTooltip}</span>
                    </div>
                    <div onClick={
                        () => {
                            handleMobileTooltipClick(<TooltipMobile
                                text={maxCoinWithConditionTooltip}
                                header={`${maxCoinValueValue}[${fullMaxCoinValueValue}]`}
                                image={maxCoinWithConditionImgHTML}
                            />
                            )
                        }
                    }
                        className={`${'skill-atk'} tooltip-container`} >
                        {maxCoinValueValue}[{fullMaxCoinValueValue}]
                        {maxCoinWithConditionImgHTML}
                        <span className={`${'entityFullInfo-tooltip'}`} >{maxCoinWithConditionTooltip}</span>
                    </div>
                    <div onClick={
                        () => {
                            handleMobileTooltipClick(<TooltipMobile
                                text={attackDefLevelTooltip}
                                header={`${attackDefLevelValue}`}
                                image={attackDefLevelImgHTML}
                            />
                            )
                        }
                    }
                        className={`${'skill-atk'} tooltip-container`} >
                        {attackDefLevelValue}
                        {attackDefLevelImgHTML}
                        <span className={`${'entityFullInfo-tooltip'}`} >{attackDefLevelTooltip}</span>
                    </div>
                    {selectedUptie === 4 && (
                        <>
                            {(minPossibleDmgValue !== 0) && <div onClick={
                                () => {
                                    handleMobileTooltipClick(<TooltipMobile
                                        text={minPossibleDmgTooltip}
                                        header={`${minPossibleDmgValue}`}
                                        image={minPossibleDmgImgHTML}
                                    />
                                    )
                                }
                            }
                                className={`${'skill-atk'} tooltip-container`} >
                                {minPossibleDmgValue}
                                {minPossibleDmgImgHTML}
                                <span className={`${'entityFullInfo-tooltip'}`} >{minPossibleDmgTooltip}</span>
                            </div>}
                            {(maxPossibleDmgValue !== 0) && <div onClick={
                                () => {
                                    handleMobileTooltipClick(<TooltipMobile
                                        text={maxPossibleDmgTooltip}
                                        header={`${maxPossibleDmgValue}`}
                                        image={maxPossibleDmgImgHTML}
                                    />
                                    )
                                }
                            }
                                className={`${'skill-atk'} tooltip-container`} >
                                {maxPossibleDmgValue}
                                {maxPossibleDmgImgHTML}
                                <span className={`${'entityFullInfo-tooltip'}`} >{maxPossibleDmgTooltip}</span>
                            </div>}
                        </>
                    )}

                    <div style={{ textDecoration: "none" }} className={`${'skill-weight'}`} >
                        <span onClick={
                            () => {
                                handleMobileTooltipClick(<TooltipMobile
                                    text={t("EntityFullInfoSkill.weightBase")}
                                    header={`${weightCoin && Array.isArray(weightCoin) && skill.index < weightCoin.length ? weightCoin[skill.index] : 0}`}
                                />
                                )
                            }
                        } className={`tooltip-container ${'skill-weight'}`} >
                            {(weightCoin && Array.isArray(weightCoin) && skill.index < weightCoin.length)
                                ? new Array(weightCoin[skill.index]).fill(0).map((e, index) => <div key={index} />)
                                : null}
                            <span className={`${'entityFullInfo-tooltip'}`} >{t("EntityFullInfoSkill.weightBase")}</span>
                        </span>
                        {attackWeightBuff !== 0 && (
                            <span onClick={
                                () => {
                                    handleMobileTooltipClick(<TooltipMobile
                                        text={t("EntityFullInfoSkill.weight")}
                                        header={`${(weightCoin && Array.isArray(weightCoin) && skill.index < weightCoin.length ? weightCoin[skill.index] : 0) + attackWeightBuff}`}
                                    />
                                    )
                                }
                            }
                                style={{ textDecoration: "none" }} className={`${'skill-weight'} skill-weight--buffed tooltip-container`} >
                                <span  >|</span>
                                {weightCoin && Array.isArray(weightCoin) && skill.index < weightCoin.length
                                    ? new Array(weightCoin[skill.index] + attackWeightBuff).fill(0).map((e, index) => <div key={index} />)
                                    : null}
                                <span className={`${'entityFullInfo-tooltip'}`} >{t("EntityFullInfoSkill.weight")}</span>
                            </span>
                        )}
                    </div>

                </div>
                <SkillCoinDescription description={testDescription} />
            </div>
        </article >
    );
};
