import React, { useEffect, useState } from 'react';
import './App.css';
import { AppRouter } from './componentslimbus/AppRouter';
import { UmamusumeRouter } from './componentsumamusume/UmamusumeRouter';
import { GameSelectionPage } from './GameSelectionPage';
import { store } from './store/store';
import { Provider } from 'react-redux';
import { BrowserRouter, Routes, Route, Navigate, useLocation } from 'react-router-dom';
import { QueryClient, QueryClientProvider } from "react-query";
import { HelmetProvider } from 'react-helmet-async';
import './i18n';

const queryClient = new QueryClient();

const OldUrlRedirect = () => {
  const location = useLocation();
  const path = location.pathname;
  if (path.startsWith('/limbus') || path.startsWith('/umamusume')) {
    return <Navigate to={`${path}${location.search}`} replace />;
  }
  return <Navigate to={`/limbus${path}${location.search}`} replace />;
};

const ClearCacheButton = () => {
  const clearCacheAndRefresh = () => {
    localStorage.clear();
    sessionStorage.clear();
    window.location.replace(window.location.origin + window.location.pathname + '?nocache=' + Date.now());
  };
  return (
    <button className="clear-cache-button" onClick={clearCacheAndRefresh}>
      Clear cache 
    </button>
  );
};

function App() {
  const [showButton] = useState(true);

  useEffect(() => {
    const handleKeyDown = (e: KeyboardEvent) => {
      if (e.ctrlKey && e.shiftKey && e.altKey) {
        e.preventDefault();
        localStorage.clear();
        sessionStorage.clear();
        window.location.reload();
      }
    };
    window.addEventListener('keydown', handleKeyDown);
    return () => window.removeEventListener('keydown', handleKeyDown);
  }, []);

  return (
    <HelmetProvider>
      <QueryClientProvider client={queryClient}>
        <Provider store={store}>
          <BrowserRouter>
            {showButton && <ClearCacheButton />}
            <Routes>
              <Route path="/" element={<Navigate to="/limbus/en/" replace />} />
              <Route path="/select-game" element={<GameSelectionPage />} />
              <Route path="/limbus/*" element={<AppRouter />} />
              <Route path="/umamusume/*" element={<UmamusumeRouter />} />
              <Route path="*" element={<OldUrlRedirect />} />
            </Routes>
          </BrowserRouter>
        </Provider>
      </QueryClientProvider>
    </HelmetProvider>
  );
}

export default App;