import React, { useState, useEffect, useMemo } from 'react';
import { useQueryClient } from "react-query";
import { useTranslation } from "react-i18next";
import { Link } from "react-router-dom";
import { SkillCoinDescription } from "../guides/text-formatter/SkillCoinDescription";
import { supabase } from '../../tools/supabaseClient';
import { IdentityInterface } from "../../store/reducers/ids-reducer";
import { EGOInterface } from "../../store/reducers/ego-reducer";
import { isIdentity } from "../../tools/isIdentity";
import './TestComponent.css';

export const TestComponent: React.FC = () => {
  const [email, setEmail] = useState("");
  const [password, setPassword] = useState("");
  const [description, setDescription] = useState("");
  const [searchQuery, setSearchQuery] = useState(""); // Состояние для поиска
  const [user, setUser] = useState<any>(null);
  const [isAdmin, setIsAdmin] = useState(false);
  const [loading, setLoading] = useState(true);

  const { i18n } = useTranslation();
  const queryClient = useQueryClient();
  
  const allIds = queryClient.getQueryData("identities") as IdentityInterface[] | null;
  const allEgo = queryClient.getQueryData("ego") as EGOInterface[] | null;

  // Функция фильтрации и объединения списков
  const filteredList = useMemo(() => {
    const combined = [...(allIds || []), ...(allEgo || [])];
    if (!searchQuery.trim()) return combined.sort((a, b) => b.releaseDate - a.releaseDate);

    const query = searchQuery.toLowerCase();
    return combined.filter(item => 
      item.nameRU?.toLowerCase().includes(query) || 
      item.nameEN?.toLowerCase().includes(query) ||
      item.imgUrl?.toLowerCase().includes(query)
    ).sort((a, b) => b.releaseDate - a.releaseDate);
  }, [allIds, allEgo, searchQuery]);

  const checkAdminStatus = async (currentUser: any) => {
    const roleInMetadata = currentUser?.app_metadata?.role === 'admin';
    if (roleInMetadata) {
      setIsAdmin(true);
      return;
    }
    const { data, error } = await supabase.from('profiles').select('is_admin').eq('id', currentUser.id).single();
    if (!error && data?.is_admin) setIsAdmin(true);
  };

  useEffect(() => {
    const initAuth = async () => {
      const { data: { session } } = await supabase.auth.getSession();
      if (session?.user) {
        setUser(session.user);
        await checkAdminStatus(session.user);
      }
      setLoading(false);
    };
    initAuth();
    const { data: { subscription } } = supabase.auth.onAuthStateChange(async (_event, session) => {
      if (session?.user) {
        setUser(session.user);
        await checkAdminStatus(session.user);
      } else {
        setUser(null);
        setIsAdmin(false);
      }
    });
    return () => subscription.unsubscribe();
  }, []);

  const handleLogin = async (e: React.FormEvent) => {
    e.preventDefault();
    setLoading(true);
    const { data, error } = await supabase.auth.signInWithPassword({ email, password });
    if (error) {
      alert("Ошибка: " + error.message);
      setLoading(false);
    }
  };

  const handleLogout = async () => {
    await supabase.auth.signOut();
    window.location.reload();
  };



  if (!user || !isAdmin) {
    return (
      <div className="auth-page-wrapper">
        <form onSubmit={handleLogin} className="auth-form">
          <h2>Admin Login</h2>
          <input className="auth-input" type="email" placeholder="Email" value={email} onChange={e => setEmail(e.target.value)} required />
          <input className="auth-input" type="password" placeholder="Пароль" value={password} onChange={e => setPassword(e.target.value)} required />
          <button type="submit" className="submit-button">Войти</button>
        </form>
      </div>
    );
  }

  return (
    <div className="admin-layout"> 
      <aside className="admin-sidebar">
        <div className="sidebar-header">
            <h3>Сущности ({filteredList.length})</h3>
            <input 
              type="text" 
              className="sidebar-search" 
              placeholder="Поиск (RU/EN)..." 
              value={searchQuery}
              onChange={(e) => setSearchQuery(e.target.value)}
            />
        </div>
        <div className="sidebar-list">
          {filteredList.map((entity, index) => {
            const isEgoEntity = !isIdentity(entity);
            const imgFolder = isEgoEntity ? "ego" : "identities";
            const name = entity.nameRU || entity.nameEN;
            const linkPath = `/limbus/${i18n.language}/${imgFolder}/${entity.imgUrl}`;

            return (
              <Link to={linkPath} key={`${imgFolder}-${entity.imgUrl}-${index}`} className="sidebar-item">
                 <div className="sidebar-img-frame">
                    <img src={`${process.env.PUBLIC_URL}/images/${imgFolder}/${entity.imgUrl}.webp`} alt="" />
                 </div>
                 <div className="sidebar-item-text">
                    <span className="sidebar-name">{name}</span>
                    <span className="sidebar-sub">{isEgoEntity ? "E.G.O" : "Identity"}</span>
                 </div>
              </Link>
            );
          })}
        </div>
      </aside>

      <main className="admin-main-content">
        <div className="admin-header">
        </div>

        <div className="editor-section">
          <h3>Редактор описаний</h3>
          <textarea 
            className="descriptionarea"
            placeholder="Введите текст..."
            value={description}
            onChange={(e) => setDescription(e.target.value)}
            wrap="soft"
          ></textarea>
        </div>
        
        <div className="preview-section">
          <h3>Предпросмотр:</h3>
          <div className="preview-grid">
            {description.split("|").map((desc, index) => (
              desc.trim() !== "" && (
                <div key={index} className="descriptionContainer">
                  <SkillCoinDescription description={desc.trim()} />
                </div>
              )
            ))}
          </div>
        </div>
      </main>
    </div>
  );
};