import React, { useEffect} from "react";
import { useNavigate, useParams } from "react-router-dom";
import { CommonPageLayout } from "./CommonPageLayout";
import { LoadingPageWrapper } from "./LoadingPageWrapper";
import { useTranslation } from "react-i18next";
import { H1Component } from "../componentslimbus/h1-component/H1Component";
import { MirrorDungeonNav } from "../componentslimbus/mirror-dungeon/nav/MirrorDungeonNav";
import { MDRouteHandler } from "../componentslimbus/mirror-dungeon/route-type-handler/MDRouteHandler";
import Analytics from "../componentslimbus/Analytics"; // Импортируем ваш компонент
import { SEOHelmet } from "./SEOHelmet";
import Sweepers from "../componentslimbus/Sweepers";

export const MirrorDungeonPage:React.FC = () => {
    const {i18n} = useTranslation();
    const params = useParams();
    const type = params['type'] || "redirect";
    const navigate = useNavigate();
    useEffect(()=>{
        if( !(["rest-stops","gifts","events"].includes(type)))  
        navigate(`/limbus/${i18n.language}/mirror-dungeon/events`);
    },[])
    const {t} = useTranslation();
    return <CommonPageLayout>
        <Sweepers/>
            <Analytics />  {/* Вставляем компонент для GA */}
            <SEOHelmet
                title="Mirror Dungeon — Limbus Company | Great Limbus Library"
                description="События, подарки и механики Mirror Dungeon в Limbus Company."
                />

            <LoadingPageWrapper queryKeys={["ego","identities","statuses","events_list","news_list", "md-gifts","md-events","chanlog", "guides"]}>
                
                <H1Component header={t("MirrorDungeonPage.header")}/>
                <MirrorDungeonNav/>
                <MDRouteHandler/>
            </LoadingPageWrapper>
    </CommonPageLayout> 
}
